package main

import (
	"encoding/json"
	"fmt"
	"io/ioutil"
	"log"
	"net/http"
	"strconv"

	"github.com/gorilla/mux"
)

type task struct {
	ID      int    `json:"ID"`
	Name    string `json:"Name"`
	Content string `json:"Content"`
}

type allTasks []task

var tasks = allTasks{
	{
		ID:      1,
		Name:    "Task One",
		Content: "Task One Content",
	},
}

func indexRouter(w http.ResponseWriter, r *http.Request) {
	json.NewEncoder(w).Encode(tasks)
	w.Header().Set("Content-Type", "application/json")
}

func createTasks(w http.ResponseWriter, r *http.Request) {
	var newTask task
	reqBody, err := ioutil.ReadAll(r.Body)

	if err != nil {
		fmt.Fprintf(w, "Kindly enter data with the task name and content only in order to update")
		fmt.Println("Error reading request body:", err)
	}

	newTask.ID = len(tasks) + 1
	tasks = append(tasks, newTask)

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusCreated)

	json.NewEncoder(w).Encode(newTask)
	json.Unmarshal(reqBody, &newTask)
}

func postTasks(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	taskID, err := strconv.Atoi(vars["id"])

	if err != nil {
		fmt.Fprintf(w, "Invalid task ID")
		return
	}

	for _, task := range tasks {
		if task.ID == taskID {
			w.Header().Set("Content-Type", "application/json")
			json.NewEncoder(w).Encode(task)
		}
	}
}

func deleteTasks(w http.ResponseWriter, r *http.Request) {
	vars := mux.Vars(r)
	taskID, err := strconv.Atoi(vars["id"])

	if err != nil {
		fmt.Fprintf(w, "Invalid task ID")
		return
	}

	for i, t := range tasks {
		if t.ID == taskID {
			tasks = append(tasks[:i], tasks[i+1:]...)
			fmt.Fprintf(w, "Task with ID %v has been deleted", taskID)
		}
	}
}

func getTasks(w http.ResponseWriter, r *http.Request) { fmt.Fprintf(w, "Welcome to the API") }

func main() {
	router := mux.NewRouter().StrictSlash(true)

	router.HandleFunc("/", getTasks)
	router.HandleFunc("/tasks", indexRouter).Methods("GET")
	router.HandleFunc("/tasks", createTasks).Methods("POST")
	router.HandleFunc("/tasks/{id}", postTasks).Methods("GET")
	router.HandleFunc("/tasks/{id}", deleteTasks).Methods("DELETE")

	fmt.Println("Server is running on port 3000")
	log.Fatal(http.ListenAndServe(":3000", router))
}
